const gemini = $input.all().find(n => n.json?.candidates)?.json; const groq = $input.all().find(n => n.json?.choices)?.json; const ctx = $('Process').first().json; let report = ''; let provider = 'mock'; if (gemini?.candidates?.[0]?.content?.parts?.[0]?.text) { report = gemini.candidates[0].content.parts[0].text; provider = 'gemini'; } else if (groq?.choices?.[0]?.message?.content) { report = groq.choices[0].message.content; provider = 'groq'; } else { const grade = ctx.roas >= 3.5 ? 'A' : ctx.roas >= 2.5 ? 'B' : ctx.roas >= 1.5 ? 'C' : 'D'; report = `## Business Report - ${new Date().toLocaleDateString()}

**Grade: ${grade}**

**Key Metrics:**
- Revenue: EGP ${ctx.totalRevenue.toLocaleString()}
- Orders: ${ctx.totalOrders} (${ctx.confirmationRate}% confirmed)
- ROAS: ${ctx.roas}x | CPA: EGP ${ctx.cpa}

**Insights:**
${ctx.anomalies.map((a) => `- ${a.message}`).join('
') || '- Performance stable'}

**Recommendations:**
${ctx.roas < 2.5 ? '1. Review and pause underperforming ad sets
' : '1. Scale winning campaigns
'}${ctx.deliveryRate < 55 ? '2. Follow up with shipping partners on delayed orders
' : '2. Maintain current shipping workflow
'}${ctx.confirmationRate < 75 ? '3. Improve confirmation rate via WhatsApp automation' : '3. Confirmation rate is healthy - great work!'}`; } return [{json:{ success: true, report, provider, metrics: { revenue: ctx.totalRevenue, orders: ctx.totalOrders, roas: ctx.roas, cpa: ctx.cpa, confirmationRate: ctx.confirmationRate, deliveryRate: ctx.deliveryRate, profitMargin: ctx.profitMargin }, anomalies: ctx.anomalies, generatedAt: new Date().toISOString() }}];
